from vex_sdk import VexClient
from openai import OpenAI
import os

vex = VexClient(api_key=os.getenv('VEX_API_KEY'))
openai_client = OpenAI()

def handle_run_complete(run_id: str, thread_id: str):
    # Get latest code artifacts
    messages = openai_client.beta.threads.messages.list(thread_id)
    code_content = '\n'.join([
        content.text.value 
        for msg in messages.data 
        for content in msg.content 
        if content.type == 'text'
    ])

    # Vex verification suite for code generation
    result = vex.verify({
        'prompt': 'Verify generated code',
        'output': code_content,
        'tasks': [
            {
                'name': 'code_safety',
                'type': 'code_safety',
                'config': {
                    'language': 'python',
                    'block_network': True,
                    'block_fs_write': True,
                    'detect_credentials': True
                }
            },
            {
                'name': 'syntax_validity',
                'type': 'syntax_check',
                'config': {'language': 'python'}
            }
        ]
    })

    if result.passed:
        print('✅ Code verified safe')
    else:
        print('❌ Vex blocked unsafe code:', result.failures)

import express from 'express';
import { Vex } from '@vex/sdk';
import OpenAI from 'openai';

const app = express();
const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
const openai = new OpenAI();

app.use(express.json());

app.post('/vex-webhook', async (req, res) => {
  const { thread_id, run_id } = req.body;

  try {
    // Extract code from thread
    const messages = await openai.beta.threads.messages.list(thread_id);
    const code = messages.data
      .flatMap(m => m.content?.map(c => (c as any).text?.value) || [])
      .join('\n');

    const verification = await vex.verify({
      prompt: 'Code generation verification',
      output: code,
      tasks: [
        {
          name: 'code_security',
          type: 'code_security',
          config: {
            language: 'python',
            sandbox: true,
            credential_scan: true,
            dependency_check: true
          }
        },
        {
          name: 'test_execution',
          type: 'sandbox_execution',
          config: {
            timeout: 30,
            memory_limit: '256MB'
          }
        }
      ]
    });

    res.json({
      passed: verification.passed,
      score: verification.score,
      issues: verification.issues
    });

  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

app.listen(3000);
